import os
import requests


def main(event):
    token = os.environ["full_access_hubspot_token"]
    deal_id = event["inputFields"]["deal_id"]

    base_url = "https://api.hubapi.com"
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json",
    }

    # -- step 1: fetch the deal --
    deal_resp = requests.get(
        f"{base_url}/crm/v3/objects/deals/{deal_id}",
        headers=headers,
        params={"properties": "amount,paid_in_full,tags"},
    )
    deal_resp.raise_for_status()
    deal_props = deal_resp.json().get("properties", {})

    # bail early if already marked paid in full
    if str(deal_props.get("paid_in_full", "")).lower() == "true":
        return {
            "outputFields": {
                "status": "skipped",
                "reason": "paid_in_full is already checked",
            }
        }

    deal_amount_raw = deal_props.get("amount")
    if not deal_amount_raw:
        return {
            "outputFields": {
                "status": "skipped",
                "reason": "no deal amount set",
            }
        }
    deal_amount = round(float(deal_amount_raw), 2)

    # check if this is a participate energy deal — they only pay 70%
    tags_raw = deal_props.get("tags") or ""
    tag_list = [t.strip().lower() for t in tags_raw.split(";") if t.strip()]
    is_participate_energy = "participate energy" in tag_list

    if is_participate_energy:
        deal_amount = round(deal_amount * 0.70, 2)

    # -- step 2: get associated invoice ids --
    assoc_resp = requests.get(
        f"{base_url}/crm/v4/objects/deals/{deal_id}/associations/invoices",
        headers=headers,
    )
    assoc_resp.raise_for_status()
    assoc_results = assoc_resp.json().get("results", [])

    if not assoc_results:
        return {
            "outputFields": {
                "status": "skipped",
                "reason": "no associated invoices found",
            }
        }

    # -- step 3: fetch each invoice and sum hs_amount_paid --
    total_paid = 0.0
    invoice_count = 0

    for assoc in assoc_results:
        inv_id = assoc.get("toObjectId")
        if not inv_id:
            continue

        inv_resp = requests.get(
            f"{base_url}/crm/v3/objects/invoices/{inv_id}",
            headers=headers,
            params={"properties": "hs_amount_paid,hs_number"},
        )
        inv_resp.raise_for_status()
        inv_props = inv_resp.json().get("properties", {})

        amount_paid = inv_props.get("hs_amount_paid") or "0"
        total_paid += float(amount_paid)
        invoice_count += 1

    total_paid = round(total_paid, 2)

    # -- step 4: compare and update if within tolerance --
    diff = abs(total_paid - deal_amount)
    tolerance = 0.05

    if diff > tolerance:
        return {
            "outputFields": {
                "status": "no_match",
                "deal_amount": deal_amount,
                "total_paid": total_paid,
                "difference": diff,
                "invoices_checked": invoice_count,
                "participate_energy": is_participate_energy,
            }
        }

    # -- step 5: check the paid_in_full box --
    update_resp = requests.patch(
        f"{base_url}/crm/v3/objects/deals/{deal_id}",
        headers=headers,
        json={"properties": {"paid_in_full": "true"}},
    )
    update_resp.raise_for_status()

    return {
        "outputFields": {
            "status": "updated",
            "deal_amount": deal_amount,
            "total_paid": total_paid,
            "difference": diff,
            "invoices_checked": invoice_count,
            "participate_energy": is_participate_energy,
        }
    }
